CREATE VIEW results.v_ventilation AS SELECT person_id, device_exposure_start_datetime AS start_time FROM cdm.device_exposure WHERE device_concept_id IN (SELECT descendant_concept_id FROM vocab.concept_ancestor WHERE ancestor_concept_id=45768131) UNION ALL SELECT person_id, procedure_datetime FROM cdm.procedure_occurrence WHERE procedure_concept_id IN (SELECT descendant_concept_id FROM vocab.concept_ancestor WHERE ancestor_concept_id=4302207);